class PricingCalculator {
    double applyDiscount(double orderTotal) {
        if (orderTotal > 500) {
            return orderTotal * 0.9;
        }
        return orderTotal;
    }

    double applyPremiumDiscount(double orderTotal) {
        if (orderTotal > 500) {
            return orderTotal * 0.85;
        }
        return applyDiscount(orderTotal);
    }
}
